endpoints.typeql:
# Domain details
match $d isa dm-domain, has id ":id";
fetch {
    "id": $d.id,
    "name": $d.name,
    "description": $d.description,
    "skill": $d.dm-skill-name,
    "task": $d.dm-skill-task,
    "created": $d.created-at
};

# Design decisions
match
    $dec isa dm-design-decision;
    $d isa dm-domain, has id ":id";
    (subject: $dec, domain: $d) isa dm-in-domain;
fetch {
    "id": $dec.id,
    "name": $dec.name,
    "type": $dec.dm-decision-type,
    "summary": $dec.dm-decision-summary
};

# Experiments
match
    $exp isa dm-experiment;
    $d isa dm-domain, has id ":id";
    (subject: $exp, domain: $d) isa dm-in-domain;
fetch {
    "id": $exp.id,
    "name": $exp.name,
    "hypothesis": $exp.dm-hypothesis,
    "status": $exp.dm-experiment-status
};

match
    $err isa dm-representation-error;
    $d isa dm-domain, has id ":id";
    (subject: $err, domain: $d) isa dm-in-domain;
fetch {
    "id": $err.id,
    "name": $err.name,
    "type": $err.dm-error-type,
    "severity": $err.dm-error-severity,
    "status": $err.dm-error-status,
    "description": $err.description
};
